import React, { useEffect, useRef } from "react";
import * as THREE from "three";
import { gsap } from "gsap";
import "./Background.scss";

interface BackgroundProps {
  darkMode: boolean;
  activeIndex: number;
}

const Background: React.FC<BackgroundProps> = ({ darkMode, activeIndex }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const sceneRef = useRef<THREE.Scene | null>(null);
  const cameraRef = useRef<THREE.PerspectiveCamera | null>(null);
  const frameIdRef = useRef<number | null>(null);

  // Groups for different themes
  const lightGroupRef = useRef<THREE.Group>(new THREE.Group());
  const darkGroupRef = useRef<THREE.Group>(new THREE.Group());

  // Seasonal subgroups
  const springGroup = useRef<THREE.Group>(new THREE.Group());
  const summerGroup = useRef<THREE.Group>(new THREE.Group());
  const autumnGroup = useRef<THREE.Group>(new THREE.Group());
  const winterGroup = useRef<THREE.Group>(new THREE.Group());

  // Helper to create textures on the fly
  const createTexture = (type: "blossom" | "leaf" | "snowflake" | "butterfly" | "sun") => {
    const canvas = document.createElement("canvas");
    canvas.width = 128; // Higher res
    canvas.height = 128;
    const ctx = canvas.getContext("2d");
    if (!ctx) return null;

    ctx.clearRect(0, 0, 128, 128);
    if (type === "blossom") {
      ctx.fillStyle = "#ffc0cb";
      ctx.beginPath();
      ctx.ellipse(64, 64, 20, 30, Math.PI / 4, 0, Math.PI * 2);
      ctx.fill();
    } else if (type === "leaf") {
      ctx.fillStyle = "#ffffff"; // Draw white, we'll color with material
      ctx.beginPath();
      ctx.moveTo(64, 20);
      ctx.quadraticCurveTo(90, 40, 64, 108);
      ctx.quadraticCurveTo(38, 40, 64, 20);
      ctx.fill();
    } else if (type === "snowflake") {
      ctx.strokeStyle = "white";
      ctx.lineWidth = 4;
      ctx.lineCap = "round";
      ctx.beginPath();
      for (let i = 0; i < 6; i++) {
        ctx.moveTo(64, 64);
        const angle = (i * Math.PI) / 3;
        ctx.lineTo(64 + Math.cos(angle) * 40, 64 + Math.sin(angle) * 40);
      }
      ctx.stroke();
    } else if (type === "butterfly") {
      ctx.fillStyle = "white";
      ctx.beginPath();
      ctx.ellipse(50, 64, 20, 25, -Math.PI / 6, 0, Math.PI * 2);
      ctx.ellipse(78, 64, 20, 25, Math.PI / 6, 0, Math.PI * 2);
      ctx.fill();
    } else if (type === "sun") {
      const grd = ctx.createRadialGradient(64, 64, 4, 64, 64, 60);
      grd.addColorStop(0, "white");
      grd.addColorStop(0.3, "rgba(255, 255, 0, 0.9)");
      grd.addColorStop(1, "transparent");
      ctx.fillStyle = grd;
      ctx.fillRect(0, 0, 128, 128);
    }
    const tex = new THREE.CanvasTexture(canvas);
    tex.needsUpdate = true;
    return tex;
  };

  useEffect(() => {
    if (!containerRef.current) return;
    console.log("Background initialized: ", { darkMode, activeIndex });

    // --- Scene Setup ---
    const scene = new THREE.Scene();
    sceneRef.current = scene;

    const camera = new THREE.PerspectiveCamera(
      75,
      window.innerWidth / window.innerHeight,
      0.1,
      1000
    );
    camera.position.z = 5;
    cameraRef.current = camera;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    containerRef.current.appendChild(renderer.domElement);
    rendererRef.current = renderer;

    // --- Groups setup ---
    scene.add(lightGroupRef.current);
    scene.add(darkGroupRef.current);

    [springGroup, summerGroup, autumnGroup, winterGroup].forEach(g => lightGroupRef.current.add(g.current));

    // --- DARK MODE ASSETS ---
    const starTex = createTexture("sun"); // Reuse circle texture for stars
    const starGeo = new THREE.BufferGeometry();
    const starCount = 4000;
    const starPos = new Float32Array(starCount * 3);
    for (let i = 0; i < starCount * 3; i++) starPos[i] = (Math.random() - 0.5) * 100;
    starGeo.setAttribute("position", new THREE.BufferAttribute(starPos, 3));
    const starMat = new THREE.PointsMaterial({ size: 0.2, map: starTex, transparent: true, opacity: 0.8, alphaTest: 0.1 });
    darkGroupRef.current.add(new THREE.Points(starGeo, starMat));

    const planetTypes = [
      { color: 0x4a90e2, size: 1.8, pos: [0, 0, 0], rings: false },     // Home
      { color: 0xf5a623, size: 4.5, pos: [18, -12, -15], rings: true }, // Skills
      { color: 0xd0021b, size: 3.2, pos: [-20, 10, -10], rings: false }, // Projects
      { color: 0x8c63e0, size: 2.5, pos: [5, 20, -20], rings: true },    // Contact
    ];

    planetTypes.forEach((p) => {
      const planet = new THREE.Mesh(
        new THREE.SphereGeometry(p.size, 64, 64),
        new THREE.MeshStandardMaterial({ color: p.color, emissive: p.color, emissiveIntensity: 0.15, roughness: 0.7 })
      );
      planet.position.set(p.pos[0], p.pos[1], p.pos[2]);
      darkGroupRef.current.add(planet);
      if (p.rings) {
        const ring = new THREE.Mesh(
          new THREE.RingGeometry(p.size * 1.6, p.size * 2.5, 64),
          new THREE.MeshBasicMaterial({ color: p.color, side: THREE.DoubleSide, transparent: true, opacity: 0.25 })
        );
        ring.rotation.x = Math.PI / 2.3;
        planet.add(ring);
      }
    });

    // --- LIGHT MODE ASSETS ---
    // Spring
    const blossomTex = createTexture("blossom");
    const blossomMat = new THREE.PointsMaterial({ size: 0.3, map: blossomTex, transparent: true, alphaTest: 0.1 });
    const blossomGeo = new THREE.BufferGeometry();
    const blossomPos = new Float32Array(500 * 3);
    for (let i = 0; i < 500 * 3; i++) blossomPos[i] = (Math.random() - 0.5) * 30;
    blossomGeo.setAttribute("position", new THREE.BufferAttribute(blossomPos, 3));
    const blossoms = new THREE.Points(blossomGeo, blossomMat);
    springGroup.current.add(blossoms);

    const bflyTex = createTexture("butterfly");
    const butterflies: THREE.Mesh[] = [];
    for(let i=0; i<12; i++) {
        const b = new THREE.Mesh(new THREE.PlaneGeometry(0.4, 0.4), new THREE.MeshBasicMaterial({ map: bflyTex, transparent: true, side: THREE.DoubleSide, color: 0xff69b4 }));
        b.position.set((Math.random()-0.5)*20, (Math.random()-0.5)*20, (Math.random()-0.5)*5);
        springGroup.current.add(b);
        butterflies.push(b);
    }

    // Summer
    const sunTex = createTexture("sun");
    const sun = new THREE.Sprite(new THREE.SpriteMaterial({ map: sunTex }));
    sun.scale.set(8, 8, 1);
    sun.position.set(10, 8, -5);
    summerGroup.current.add(sun);

    // Autumn
    const leafTex = createTexture("leaf");
    const leafMeshes: THREE.Mesh[] = [];
    for(let i=0; i<150; i++) {
        const l = new THREE.Mesh(new THREE.PlaneGeometry(0.3, 0.3), new THREE.MeshBasicMaterial({ map: leafTex, transparent: true, color: Math.random() > 0.5 ? 0xd2691e : 0xff8c00, side: THREE.DoubleSide }));
        l.position.set((Math.random()-0.5)*30, (Math.random()-0.5)*30, (Math.random()-0.5)*10);
        autumnGroup.current.add(l);
        leafMeshes.push(l);
    }

    // Winter
    const snowTex = createTexture("snowflake");
    const snowGeo = new THREE.BufferGeometry();
    const snowPos = new Float32Array(1500 * 3);
    for (let i = 0; i < 1500 * 3; i++) snowPos[i] = (Math.random() - 0.5) * 30;
    snowGeo.setAttribute("position", new THREE.BufferAttribute(snowPos, 3));
    const snow = new THREE.Points(snowGeo, new THREE.PointsMaterial({ size: 0.2, map: snowTex, transparent: true, alphaTest: 0.1 }));
    winterGroup.current.add(snow);

    const snowman = new THREE.Group();
    const snowMat = new THREE.MeshPhongMaterial({ color: 0xffffff });
    const b1 = new THREE.Mesh(new THREE.SphereGeometry(1, 32, 32), snowMat);
    const b2 = new THREE.Mesh(new THREE.SphereGeometry(0.7, 32, 32), snowMat); b2.position.y = 1.3;
    const b3 = new THREE.Mesh(new THREE.SphereGeometry(0.4, 32, 32), snowMat); b3.position.y = 2.2;
    const nose = new THREE.Mesh(new THREE.ConeGeometry(0.08, 0.3, 32), new THREE.MeshPhongMaterial({ color: 0xffa500 }));
    nose.rotation.x = Math.PI/2; nose.position.set(0, 2.2, 0.4);
    snowman.add(b1, b2, b3, nose);
    snowman.position.set(-8, -4, -2);
    winterGroup.current.add(snowman);

    // Lighting
    scene.add(new THREE.AmbientLight(0xffffff, 0.5));
    const pLight = new THREE.PointLight(0xffffff, 1.2);
    pLight.position.set(10, 10, 10);
    scene.add(pLight);

    // Render loop
    const animate = (time: number) => {
        frameIdRef.current = requestAnimationFrame(animate);
        if (darkMode) {
            darkGroupRef.current.rotation.y += 0.0003;
            darkGroupRef.current.children.forEach(p => { if(p instanceof THREE.Mesh) p.rotation.y += 0.005; });
        } else {
            blossoms.position.y -= 0.015; if (blossoms.position.y < -15) blossoms.position.y = 15;
            butterflies.forEach((b, i) => { b.position.x += Math.cos(time*0.001+i)*0.01; b.position.y += Math.sin(time*0.002+i)*0.02; });
            leafMeshes.forEach(l => { l.position.y -= 0.02; l.rotation.x += 0.01; if(l.position.y < -15) l.position.y = 15; });
            snow.position.y -= 0.03; if(snow.position.y < -15) snow.position.y = 15;
            sun.scale.setScalar(8 + Math.sin(time*0.002)*0.5);
        }
        renderer.render(scene, camera);
    };
    animate(0);

    const handleResize = () => {
        camera.aspect = window.innerWidth / window.innerHeight;
        camera.updateProjectionMatrix();
        renderer.setSize(window.innerWidth, window.innerHeight);
    };
    window.addEventListener("resize", handleResize);

    return () => {
        window.removeEventListener("resize", handleResize);
        if (frameIdRef.current) cancelAnimationFrame(frameIdRef.current);
        renderer.dispose();
        if (containerRef.current) containerRef.current.innerHTML = "";
    };
  }, []);

  useEffect(() => {
    if (!sceneRef.current || !cameraRef.current) return;
    
    // Visibility toggles
    lightGroupRef.current.visible = !darkMode;
    darkGroupRef.current.visible = darkMode;

    gsap.to(lightGroupRef.current.position, { y: darkMode ? -25 : 0, duration: 1.2, ease: "power2.inOut" });
    gsap.to(darkGroupRef.current.position, { y: darkMode ? 0 : 25, duration: 1.2, ease: "power2.inOut" });

    if (darkMode) {
        const cameraTargets = [
            { x: 0, y: 0, z: 35 },     // All planets visible
            { x: 16, y: -10, z: -5 },  // Focus Skills
            { x: -18, y: 10, z: 0 },   // Focus Projects
            { x: 4, y: 18, z: -10 }    // Focus Contact
        ];
        const target = cameraTargets[activeIndex] || cameraTargets[0];
        gsap.to(cameraRef.current.position, { x: target.x, y: target.y, z: target.z, duration: 3.5, ease: "power2.inOut" });
    }

    const seasonGroups = [springGroup, summerGroup, autumnGroup, winterGroup];
    seasonGroups.forEach((g, i) => {
        const isActive = activeIndex === i && !darkMode;
        if (isActive) g.current.visible = true;
        gsap.to(g.current.scale, {
            x: isActive ? 1 : 0.001, y: isActive ? 1 : 0.001, z: isActive ? 1 : 0.001,
            duration: 1.2, ease: "power2.inOut",
            onComplete: () => { if(!isActive) g.current.visible = false; }
        });
    });
  }, [darkMode, activeIndex]);

  return <div ref={containerRef} className="background-container" />;
};

export default Background;
